import java.util.Scanner;

public class SecureBufferExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter a string: ");
        String userInput = scanner.nextLine();

        // Set a maximum length for user input
        int maxLength = 10;

        if (userInput.length() > maxLength) {
            System.out.println("Input exceeds maximum allowed length.");
            return;
        }

        // Use StringBuilder to store user input dynamically
        StringBuilder buffer = new StringBuilder(userInput);

        System.out.println("Buffer content: " + buffer.toString());

        // Perform some operations with the buffer
    }
}

